  loadBowlingStats = task({ group: this.analyticsLoaders }, async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/bowling`)
    return response.json()
  })

  loadFieldingStats = task({ group: this.analyticsLoaders }, async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/fielding`)
    return response.json()
  })

  <template>
