import { task, waitForEvent } from 'ember-concurrency'
import { registerDestructor } from '@ember/destroyable'

export default class LiveScoreSocket extends Component {
  @tracked liveScore = null
  ws = null

  connectToLiveScore = task(async () => {
    this.ws = new WebSocket(`wss://live.spordium.com/matches/${this.args.matchId}`)

    await waitForEvent(this.ws, 'open')
    console.log('WebSocket connected')

    while (true) {
      const event = await waitForEvent(this.ws, 'message')
      const data = JSON.parse(event.data)
      if (data.type === 'score_update') {
        this.liveScore = data.payload
      }
    }
  })

  constructor(owner, args) {
    super(owner, args)
    registerDestructor(this, () => {
      this.connectToLiveScore.cancelAll()
      this.ws?.close()
    })
  }

  <template>
    <button type="button" {{on "click" (fn this.connectToLiveScore.perform)}}>
      Connect Live
    </button>
    {{#if this.liveScore}}
      <p>Live: {{this.liveScore.runs}}/{{this.liveScore.wickets}} ({{this.liveScore.overs}} ov)</p>
    {{/if}}
  </template>
}
```
`waitForEvent()` is ember-concurrency's cancellation-aware alternative to adding DOM event listeners manually. The infinite loop listening for `'message'` events works perfectly with ember-concurrency because `waitForEvent()` is an `await` point — cancellation is handled cleanly. The destructor closes the WebSocket and cancels the task when the component unmounts.

