  refreshScore = task(async () => {
    const res = await fetch(`/api/matches/${this.args.matchId}/score`)
    if (!res.ok) throw new Error('Refresh failed')
    return res.json()
  })

  <template>
    <div class="flex items-center gap-4">
      <button
        type="button"
        {{on "click" (fn this.refreshScore.perform)}}
        disabled={{this.refreshScore.isRunning}}
      >
        Refresh Score
      </button>

      <span class="text-gray-400 text-sm">
        Refreshed {{this.refreshScore.performCount}} times
      </span>
    </div>

    {{#if this.refreshScore.isRunning}}
      <p>Refreshing...</p>
    {{else if this.refreshScore.last.value}}
      <p>Score: {{this.refreshScore.last.value.runs}}/{{this.refreshScore.last.value.wickets}}</p>
    {{/if}}
  </template>
}
```
`task.performCount` is a built-in property that increments each time `.perform()` is called, regardless of whether the task succeeds, fails, or is dropped. It does not reset between component mounts. It's useful for showing refresh counts, attempt numbers, or analytics without needing a separate `@tracked` counter.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class ScoreboardStatus extends Component {
  syncScoreboard = task(async () => {
    const res = await fetch(`/api/matches/${this.args.matchId}/sync`, {
      method: 'POST',
    })
    if (!res.ok) throw new Error('Sync failed')
    return res.json()
  })

  <template>
    <div class="p-4 border rounded">
      {{#if this.syncScoreboard.isRunning}}
        <p class="text-blue-500 animate-pulse">⟳ Syncing scoreboard...</p>
      {{else if this.syncScoreboard.last.error}}
        <p class="text-red-500">✗ Sync failed: {{this.syncScoreboard.last.error.message}}</p>
      {{else if this.syncScoreboard.last.value}}
        <p class="text-green-500">✓ Synced at {{this.syncScoreboard.last.value.syncedAt}}</p>
      {{else if this.syncScoreboard.isIdle}}
        <p class="text-gray-400">Ready to sync</p>
      {{/if}}

      <button
        type="button"
        class="mt-2 px-4 py-2 bg-blue-500 text-white rounded"
        {{on "click" (fn this.syncScoreboard.perform)}}
        disabled={{this.syncScoreboard.isRunning}}
      >
        Sync Now
      </button>
    </div>
  </template>
}
```
`task.isIdle` is `true` when no instances of the task are currently running. Before the first `.perform()`, both `task.isIdle` is `true` and `task.last` is `null`. This makes `isIdle` the right property to check for an initial 'Ready' prompt. The four-state check (`isRunning → last.error → last.value → isIdle`) covers every possible task state.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class ExplicitStateMatch extends Component {
  @tracked isLoading = false
  @tracked matchData = null
  @tracked errorMessage = null

  fetchMatch = task(async (matchId) => {
    this.isLoading = true
    this.errorMessage = null
    this.matchData = null

    try {
      const res = await fetch(`/api/matches/${matchId}`)
      if (!res.ok) throw new Error(`HTTP ${res.status}: ${res.statusText}`)
      this.matchData = await res.json()
    } catch (err) {
      this.errorMessage = err.message
    } finally {
      this.isLoading = false
    }
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchMatch.perform @matchId)}}>
      Load Match
    </button>

    {{#if this.isLoading}}
      <div class="skeleton h-16 bg-gray-100 animate-pulse rounded"></div>
    {{else if this.errorMessage}}
      <p class="text-red-500">{{this.errorMessage}}</p>
    {{else if this.matchData}}
      <h2>{{this.matchData.title}}</h2>
      <p>Venue: {{this.matchData.venue}}</p>
      <p>Date: {{this.matchData.scheduledAt}}</p>
    {{/if}}
  </template>
}
```
The explicit `@tracked` loading/result/error pattern is more verbose than `task.last.value`, but gives you full control over state transitions and is easier to understand for developers unfamiliar with ember-concurrency. The `finally` block guarantees `isLoading` resets to `false` even when the fetch throws. Use this pattern when other parts of the component or template need to react to these states independently.
